const rawData = fs.readFileSync("output/tracking.json", "utf8");

// convert json string -> js object
const tracking = JSON.parse(rawData);


const filtered = tracking
//   .filter(({ state }) => state === "TX")
  .map((item, index, arr) => {
    const prev = arr[index - 1];

    return {
      date: item.date,
      odometr: item.odometr,
      diff: prev ? item.odometr - prev.odometr : null,
      state: item.state,
      driverId: item.driverId,
    };
  });

// console.table(filtered);

const totalDiff = filtered.reduce((sum, item) => sum + (item.diff || 0), 0);
console.log("Total distance traveled:", totalDiff);
const headers = ["idx", "date", "odometr", "diff", "state", "driverId"];

const csvRows = [
  headers.join(","),

  ...filtered.map(row =>
    headers.map(header => row[header]).join(",")
  )
];

const csvContent = csvRows.join("\n");

// write file
// fs.writeFileSync("output/filtered6.csv", csvContent);

